using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF9 renamed the default discriminator from "Discriminator" to "$type".
            // Existing 500K documents use the old name, and direct SQL queries
            // reference c.Discriminator — keep the EF8-era property name.
            entity.HasDiscriminator<string>("Discriminator");

            // EF9 changed id format from "Product|123" to "123".
            // Existing documents use the compound format — preserve it.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // Removed HasIndex — EF9 Cosmos provider now throws at startup.
        // Cosmos DB indexing is managed via the container's indexing policy
        // (Azure Portal / Bicep / Terraform), not through EF Core.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

